        { "order": 0, "keyword": "Given", "text": "Kullanıcı internet bankacılığına giriş yapmıştır" },
        { "order": 1, "keyword": "And", "text": "Vadesiz hesap bakiyesi transfer tutarından yüksektir" },
        { "order": 2, "keyword": "When", "text": "EFT menüsünden transfer işlemi başlatır" },
        { "order": 3, "keyword": "Then", "text": "Transfer başarılı mesajı ve dekont numarası görüntülenir" }
    ]
}

{
    "analysis_text": "İnternet bankacılığı fatura ödeme modülü: Kullanıcı elektrik, su, doğalgaz, telefon ve internet faturalarını ödeyebilir. Otomatik ödeme talimatı verebilir. Fatura sorgulama yapabilir. Ödeme makbuzu alabilir. Geçmiş ödemelerini listeleyebilir.",
    "extra_instructions": "Her fatura tipi için ayrı senaryo üret. Negatif senaryoları da dahil et (yetersiz bakiye, hatalı abone no)."
}

