            "steps": [
                { "keyword": "Given", "text": "Kullanıcı giriş yapmıştır" },
                { "keyword": "When", "text": "Fatura ödeme menüsüne gider" },
                { "keyword": "Then", "text": "Ödeme başarılı olur" }
            ]
        }
    ]
}

{
